import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertThrows;

public class CSVFormatTest {

    @Test
    public void testWithDelimiter_ValidDelimiter() {
        // Given
        char delimiter = ',';
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat newFormat = csvFormat.withDelimiter(delimiter);

        // Then
        assertEquals(delimiter, newFormat.getDelimiter());
    }

    @Test
    public void testWithDelimiter_InvalidDelimiter_LineBreak() {
        // Given
        char delimiter = '\n';
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When/Then
        IllegalArgumentException exception = assertThrows(IllegalArgumentException.class, () -> csvFormat.withDelimiter(delimiter));
        assertEquals("The delimiter cannot be a line break", exception.getMessage());
    }

